 10→class ErrorBoundary extends React.Component {
 11→  state = { error: null };
 12→  static getDerivedStateFromError(error) {
 13→    return { error };
 14→  }
 15→  render() {
 16→    if (this.state.error) {
 17→      return <div>Error: {this.state.error.message}</div>;
 18→    }
 19→    return this.props.children;
 20→  }
 21→}
