230→export const uploadJournalContentService = async(
231→    content,
232→    title,
233→    userId,
234→    remixSourceJournalId = null,
235→    isRemix = false,
236→    promptId = null
237→) =>{
238→    if(!userId){
239→        console.error('userId is undefined');
240→        throw {status: 400, error: 'userId is undefined'};
241→    }
242→
243→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
244→
245→    if(!trimmedTitle){
246→        console.error('title is missing!');
247→        throw {status: 400, error: 'title is missing!'};
248→    }
249→
250→    const shouldSaveRemixMetadata = Boolean(
251→        remixSourceJournalId
252→        && typeof remixSourceJournalId === 'string'
253→        && remixSourceJournalId.trim()
254→    );
255→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
256→
257→    if(!content){
258→        console.error('content is missing for text post!');
259→        throw {status: 400, error: 'content is missing for text post'};
260→    }
261→
262→    const parseData = parseTextContentSafely(content);
263→    if(!parseData){
264→        console.error('error while parsing text content data');
265→        throw {status: 400, error: 'error while parsing text content data'};
266→    }
267→
268→    const embeddingBody = parseData.wholeText || '';
269→    const preview_text = parseData.slicedText || '';
270→    const thumbnail_url = parseData.firstImage?.src || null;
271→    const reading_time = Math.ceil((embeddingBody.trim().split(/\s+/).length) / 150) || 1;
272→    const payload = {
273→        user_id: userId,
274→        title: trimmedTitle,
275→        post_type: POST_TYPE_TEXT,
276→        content: content,
277→        preview_text,
278→        thumbnail_url,
279→        reading_time,
280→    };
281→
282→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
283→
284→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
285→        console.error('error while generating embeddings on a post!');
286→        throw {status: 400, error: 'error while generating embeddings on a post!'};
287→    }
288→
289→    const insertPayload = {
290→        ...payload,
291→        embeddings: embeddingResult
292→    };
293→
294→    if(normalizedIsRemix){
295→        insertPayload.is_remix = true;
296→    }
297→    if(shouldSaveRemixMetadata){
298→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
299→    }
300→    if(promptId){
301→        const parsedPromptId = parseInt(promptId, 10);
302→        if(!isNaN(parsedPromptId)){
303→            insertPayload.prompt_id = parsedPromptId;
304→        }
305→    }
306→
307→    let insertResult = await supabase
308→    .from('journals')
309→    .insert(insertPayload)
310→    .select('id')
311→    .single();
312→
313→    let error = insertResult.error;
314→
315→    if(error){
316→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
317→        if(missingRemixColumns){
318→            const fallbackPayload = {
319→                ...payload,
320→                embeddings: embeddingResult
321→            };
322→
323→            insertResult = await supabase
324→            .from('journals')
325→            .insert(fallbackPayload)
326→            .select('id')
327→            .single();
328→            error = insertResult.error;
329→        }
330→    }
331→
332→    if(error){
333→        console.error('supabase error while uploading content:',error.message);
334→        throw {status: 500, error: 'supabase error while uploading content'};
335→    }
336→
337→    const journalId = insertResult.data?.id;
338→
339→    // Non-fatal: send mention notifications
340→    if(journalId){
341→        try {
342→            const mentionedUserIds = extractMentionUserIds(content);
343→            const filtered = mentionedUserIds
344→                .filter(id => id !== userId)
345→                .slice(0, 50);
346→
347→            if(filtered.length > 0){
348→                const notifRows = filtered.map(receiverId => ({
349→                    sender_id: userId,
350→                    receiver_id: receiverId,
351→                    type: 'mention',
352→                    journal_id: journalId,
353→                    read: false
354→                }));
355→
356→                const {error: notifError} = await supabase
357→                    .from('notifications')
358→                    .insert(notifRows);
359→
360→                if(notifError){
361→                    console.error('[mentions] new post: insert failed:', notifError.message);
362→                }
363→            }
364→        } catch (mentionErr) {
365→            console.error('[mentions] new post error:', mentionErr?.message || mentionErr);
366→        }
367→    }
368→
369→    // Non-fatal: record publish for writing streak
370→    let streakResult = null;
371→    try {
372→        const { recordPublishForStreak } = await import('./streakService.js');
373→        streakResult = await recordPublishForStreak(userId);
374→    } catch (streakErr) {
375→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
376→    }
377→
378→    return { success: true, streakResult };
379→}
