381→export const updateJournalService = async(content, title, journalId, userId) => {
382→    if(!journalId){
383→        console.error('journalid is undefined');
384→        throw {status: 400, error: 'journalId is undefined'}
385→    }
386→
387→    if(!userId){
388→        console.error('userId is undefined')
389→        throw({status: 400, error: 'userId is undefined'})
390→    }
391→
392→    const {data: existingJournal, error: existingJournalError} = await supabase
393→    .from('journals')
394→    .select('id, user_id, content, title, post_type')
395→    .eq('id', journalId)
396→    .eq('user_id', userId)
397→    .maybeSingle();
398→
399→    if(existingJournalError){
400→        console.error('failed to fetch existing journal for update', existingJournalError.message);
401→        throw {status: 500, error: 'failed to fetch existing journal for update'};
402→    }
403→
404→    if(!existingJournal){
405→        console.error('journal not found for update');
406→        throw {status: 404, error: 'journal not found for update'};
407→    }
408→
409→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
410→    if(!resolvedTitle){
411→        console.error('title is undefined');
412→        throw {status: 400, error: 'title is undefined'};
413→    }
414→
415→    let resolvedContent = existingJournal.content;
416→    if(typeof content === 'string' && content.trim()){
417→        resolvedContent = content;
418→    }
419→
420→    if(!resolvedContent){
421→        console.error('text content is missing for text post update');
422→        throw {status: 400, error: 'text content is missing for text post update'};
423→    }
424→
425→    const parseData = parseTextContentSafely(resolvedContent);
426→    if(!parseData){
427→        console.error('failed to parse text content for update');
428→        throw {status: 400, error: 'failed to parse text content for update'};
429→    }
430→
431→    const embeddingBody = parseData.wholeText || '';
432→    const preview_text = parseData.slicedText || '';
433→    const thumbnail_url = parseData.firstImage?.src || null;
434→    const reading_time = Math.ceil((embeddingBody.trim().split(/\s+/).length) / 150) || 1;
435→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
436→
437→    if(!embeddings || !Array.isArray(embeddings) || embeddings.length === 0){
438→        console.error('failed to generate embeddings')
439→        throw {status: 400, error: 'failed to generate embeddings'};
440→    }
441→
442→    const journalData = {
443→        content: resolvedContent,
444→        title: resolvedTitle,
445→        post_type: POST_TYPE_TEXT,
446→        embeddings: embeddings,
447→        preview_text,
448→        thumbnail_url,
449→        reading_time,
450→    }
451→
452→    const {data, error} = await supabase
453→    .from('journals')
454→    .update(journalData)
455→    .eq('id', journalId)
456→    .eq('user_id', userId)
457→
458→    if(error){
459→        console.error('supabase error while uploading content:', error.message);
460→        throw{status: 500, error: 'supabase error while uploading content'};
461→    }
462→
463→    // Non-fatal: send mention notifications on edit
464→    try {
465→        const mentionedUserIds = extractMentionUserIds(resolvedContent);
466→        const filtered = mentionedUserIds
467→            .filter(id => id !== userId)
468→            .slice(0, 50);
469→
470→        // Remove old mention notifications for this journal to avoid duplicates
471→        const { error: deleteError } = await supabase
472→            .from('notifications')
473→            .delete()
474→            .eq('type', 'mention')
475→            .eq('journal_id', journalId);
476→
477→        if (deleteError) console.error('[mentions] edit: clear old failed:', deleteError.message);
478→
479→        if (filtered.length > 0) {
480→            const notifRows = filtered.map(receiverId => ({
481→                sender_id: userId,
482→                receiver_id: receiverId,
483→                type: 'mention',
484→                journal_id: journalId,
485→                read: false
486→            }));
487→
488→            const { error: notifError } = await supabase
489→                .from('notifications')
490→                .insert(notifRows);
491→
492→            if (notifError) console.error('[mentions] edit: insert failed:', notifError.message);
493→        }
494→    } catch (mentionErr) {
495→        console.error('[mentions] edit error:', mentionErr?.message || mentionErr);
496→    }
497→
498→    return true;
499→}
