563→        throw {status: 400, error: 'no valid fields to update'};
564→    }
565→
566→    const {error} = await supabase
567→        .from('users')
568→        .update(payload)
569→        .eq('id', userId);
570→
571→    if(error){
572→        console.error('supabase error updating interests:', error.message);
573→        throw {status: 500, error: 'failed to update interests'};
574→    }
575→
576→    // Await embedding so it's in the DB before response (feed refetch needs it)
577→    if(Array.isArray(writingInterests) && writingInterests.length > 0){
578→        await updateUserInterestsEmbedding(userId, writingInterests);
579→    }
580→
581→    return true;
582→}
