 41→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null}) => {
 42→    const [editor] = useLexicalComposerContext();
 43→    const [editorState, setEditorState] = useState(null);
 44→    const [hasContent, setHasContent] = useState(false);
 45→    const [isSending, setIsSending] = useState(false);
 46→
 47→    const {session, user} = useAuth();
 48→
 49→    const queryClient = useQueryClient();
 50→    const userId = user?.userData?.[0]?.id || null;
 51→
 52→    const invalidateCreatedJournalQueries = useCallback(async() => {
 53→        const invalidations = [
 54→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
 55→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
 56→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
 57→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
 58→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
 59→        ];
 60→
 61→        if(userId){
 62→            invalidations.push(
 63→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
 64→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
 65→            );
 66→        }
 67→
 68→        await Promise.allSettled(invalidations);
 69→    }, [queryClient, userId]);
 70→
 71→    const handleClickSave = async(e, title) =>{
 72→        e.stopPropagation();
 73→        setIsSending(true)
 74→        try {
 75→            const formdata = new FormData();
 76→            if(title && editorState){
 77→                formdata.append('title', title)
 78→                formdata.append('content', editorState)
 79→            }
 80→            if(promptId){
 81→                formdata.append('prompt_id', promptId);
 82→            }
 83→            const saveData = await saveJournal(session?.access_token, formdata)
 84→
 85→            if(saveData){
 86→                await invalidateCreatedJournalQueries();
 87→                setHasContent(false)
 88→                onCloseOnSave();
 89→                addUploadImagesPath([])
 90→            }
 91→        } catch (error) {
 92→            console.error("Error saving journal:", error);
 93→        }finally {
 94→            setIsSending(false)
 95→        }
 96→
 97→    }
 98→
 99→    const onchange = useCallback((state) => {
100→        const jsonb = JSON.stringify(state.toJSON());
101→        setEditorState(jsonb)
102→
103→        state.read(() => {
104→            const root = $getRoot();
105→
106→            const children = root.getChildren();
107→
108→            const hasEnoughParagraphNodes = children.length > 1
109→            const hasParargraphSize = children[0]?.__size > 0
110→
111→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
112→            setHasContent(hasContent);
113→
114→            // Calculate word count
115→            const text = root.getTextContent().trim();
116→            const words = text ? text.split(/\s+/).length : 0;
117→            setWordCount(words);
118→        })
119→    }, [setWordCount])
120→
121→    return(
122→        <>
123→        {/* Toolbar above content */}
124→        <div className="toolbar-wrapper">
125→            <ToolBar addUploadedImagePath={addUploadImagesPath}/>
126→        </div>
127→
128→        {/* Bar loader directly under toolbar */}
129→        <div className="editor-loader-wrapper">
130→            {isSending && (
131→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
132→            )}
133→        </div>
134→
135→        {/* Editor content area */}
136→        <div className="editor-shell">
137→            <RichTextPlugin
138→            contentEditable={
139→            <ContentEditable
140→            className="editor-input"
141→            aria-placeholder="Write your thoughts here..."
142→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
143→            }
144→            ErrorBoundary={LexicalErrorBoundary}
145→            />
146→
147→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
148→            <MentionPlugin/>
149→            <HistoryPlugin/>
150→            <OnChangePlugin onChange={onchange}/>
151→
152→        </div>
153→
154→        {/* Footer: word count + save */}
155→        <div className='editor-footer'>
156→            <span className="editor-word-count">
157→                {wordCount} {wordCount === 1 ? 'word' : 'words'}
158→            </span>
159→            <button disabled={!title || !hasContent || isSending} onClick={(e) =>handleClickSave(e, title)} className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}>
160→                Share
161→            </button>
162→        </div>
163→        </>
164→    )
165→}
166→
167→export default EditorInner;
