201→export const getStoryByIdService = async (storyId, userId) => {
202→    if (!storyId) {
203→        throw { status: 400, error: 'storyId is required' };
204→    }
205→
206→    const { data: story, error } = await supabase
207→        .from('stories')
208→        .select(STORY_SELECT_COLUMNS)
209→        .eq('id', storyId)
210→        .single();
211→
212→    if (error || !story) {
213→        console.error('supabase error fetching story:', error?.message);
214→        throw { status: 404, error: 'story not found' };
215→    }
216→
217→    // Non-author can't see private stories
218→    if (story.privacy === 'private' && story.author_id !== userId) {
219→        throw { status: 404, error: 'story not found' };
220→    }
221→
222→    // Fetch author profile + chapters in parallel
223→    const [authorMap, chapResult] = await Promise.all([
224→        fetchAuthorProfiles([story.author_id]),
225→        supabase
226→            .from('chapters')
227→            .select('id, chapter_number, title, word_count, status, published_at, created_at')
228→            .eq('story_id', storyId)
229→            .order('chapter_number', { ascending: true }),
230→    ]);
231→
232→    if (chapResult.error) {
233→        console.error('supabase error fetching chapters:', chapResult.error.message);
234→    }
235→
236→    // Filter chapters for non-authors
237→    const isAuthor = story.author_id === userId;
238→    const chapters = chapResult.data || [];
239→    const visibleChapters = isAuthor
240→        ? chapters
241→        : chapters.filter(c => c.status === 'published');
242→
243→    // Fetch user flags
244→    let hasVoted = false;
245→    let inLibrary = false;
246→    let readingProgress = null;
247→
248→    if (userId) {
249→        const [voteRes, libRes, progressRes] = await Promise.all([
250→            supabase.from('story_votes').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
251→            supabase.from('story_library').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
252→            supabase.from('reading_progress').select('chapter_id, scroll_position, last_read_at').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
253→        ]);
254→
255→        hasVoted = !!voteRes.data;
256→        inLibrary = !!libRes.data;
257→        readingProgress = progressRes.data || null;
258→    }
259→
260→    return {
261→        ...decorateStoryMedia(stripEmbedding(story), 'detail'),
262→        users: authorMap[story.author_id] || null,
263→        chapters: visibleChapters,
264→        has_voted: hasVoted,
265→        in_library: inLibrary,
266→        reading_progress: readingProgress,
267→        is_author: isAuthor,
268→    };
269→};
