223→export const deleteChapterService = async (storyId, chapterId, userId) => {
224→    if (!storyId || !chapterId || !userId) {
225→        throw { status: 400, error: 'storyId, chapterId, and userId are required' };
226→    }
227→
228→    await verifyStoryOwnership(storyId, userId);
229→
