244→export const reorderChaptersService = async (storyId, userId, chapterOrder) => {
245→    if (!storyId || !userId) {
246→        throw { status: 400, error: 'storyId and userId are required' };
247→    }
248→    if (!Array.isArray(chapterOrder) || chapterOrder.length === 0) {
249→        throw { status: 400, error: 'chapterOrder must be a non-empty array of chapter ids' };
250→    }
251→
252→    await verifyStoryOwnership(storyId, userId);
253→
254→    // Update each chapter's number based on position in array
255→    const updates = chapterOrder.map((chapterId, index) =>
256→        supabase
257→            .from('chapters')
258→            .update({ chapter_number: index + 1 })
259→            .eq('id', chapterId)
260→            .eq('story_id', storyId)
261→    );
262→
263→    const results = await Promise.all(updates);
264→    const failed = results.find(r => r.error);
265→    if (failed) {
266→        console.error('supabase error reordering chapters:', failed.error.message);
267→        throw { status: 500, error: 'failed to reorder chapters' };
268→    }
269→
270→    return { message: 'chapters reordered' };
271→};
