 10→const StoryChapterManager = () => {
 11→    const { storyId } = useParams();
 12→    const navigate = useNavigate();
 13→    const { session } = useAuth();
 14→    const token = session?.access_token;
 15→
 16→    const { data: story, isLoading } = useStoryDetail(storyId, token);
 17→    const createChapter = useCreateChapter(token);
 18→    const updateChapter = useUpdateChapter(token);
 19→    const deleteChapter = useDeleteChapter(token);
 20→    const reorderChapters = useReorderChapters(token);
 21→
 22→    const [draggedIdx, setDraggedIdx] = useState(null);
 23→    const [showNewChapterInput, setShowNewChapterInput] = useState(false);
 24→    const [newChapterTitle, setNewChapterTitle] = useState('');
 25→
 26→    const chapters = story?.chapters || [];
 27→
 28→    const handleAddChapter = () => {
 29→        const title = newChapterTitle.trim() || `Chapter ${chapters.length + 1}`;
 30→        createChapter.mutate({ storyId, title }, {
 31→            onSuccess: () => {
 32→                setNewChapterTitle('');
 33→                setShowNewChapterInput(false);
 34→            },
 35→        });
 36→    };
 37→
 38→    const handleNewChapterKeyDown = (e) => {
 39→        if (e.key === 'Enter') {
 40→            e.preventDefault();
 41→            handleAddChapter();
 42→        } else if (e.key === 'Escape') {
 43→            setShowNewChapterInput(false);
 44→            setNewChapterTitle('');
 45→        }
 46→    };
 47→
 48→    const handleToggleStatus = (chapter) => {
 49→        const newStatus = chapter.status === 'published' ? 'draft' : 'published';
 50→        updateChapter.mutate({
 51→            storyId,
 52→            chapterId: chapter.id,
 53→            data: { status: newStatus },
 54→        });
 55→    };
 56→
 57→    const handleDeleteChapter = (e, chapter) => {
