 63→
 64→    // Drag & drop reorder
 65→    const handleDragStart = useCallback((idx) => {
 66→        setDraggedIdx(idx);
 67→    }, []);
 68→
 69→    const handleDragOver = useCallback((e) => {
 70→        e.preventDefault();
 71→    }, []);
 72→
 73→    const handleDrop = useCallback((targetIdx) => {
 74→        if (draggedIdx === null || draggedIdx === targetIdx) {
 75→            setDraggedIdx(null);
