109→            transition={{ duration: 0.2 }}
110→        >
111→            <div className="chapter-manager-header">
112→                <button className="chapter-manager-back" onClick={() => navigate('/home/stories/dashboard')}>
113→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
