170→            </div>
171→
172→            {chapters.length === 0 ? (
173→                <div className="chapter-manager-empty">
174→                    <p>No chapters yet. Add your first chapter to start writing.</p>
175→                </div>
176→            ) : (
177→                <div className="chapter-manager-list">
